  ('police-3218f787-moex-00167', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法增修條文第10條第7項及第9項之規定，國家對於身心障礙者及退役軍人，應提供 特別之保障及照顧。依司法院大法官解釋意旨，下列敘述何者正確？', '["立法者制定相關法律給予身心障礙者及退役軍人特別保障，其立法目的合憲", "政府採購法規定得標廠商應強制聘僱一定比例之身心障礙者及原住民，未及於退役軍人， 違反上述增修條文規定", "基於上述增修條文規定，退役軍人得請求國家應於國立大學之招生簡章中規定退役軍人錄 取之保障名額", "法律為保障視障者之工作權，排除其他身心障礙者及非視障者從事按摩業之就業機會，符 合平等保障"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00168', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法與增修條文規定，下列何者並無獨立行使職權之保障？', '["考試委員", "法官", "監察委員", "國安會秘書長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00169', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，有關應考試服公職權，下列敘述何者錯誤？', '["國家須設置客觀公平之考試制度，係為實踐憲法保障人民應考試服公職權利之意旨", "就人民應考試服公職權所為之差別待遇，司法應採較為嚴格之審查基準", "以警大容訓量有限為由，排除一般生於警大完成訓練之機會，係屬重要公益", "將一般生一律安排至警專受訓之手段，與擇優選才目的之達成間難謂具實質關聯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00170', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，下列何者不是地方自治之權限？', '["自治組織權", "財政自主權", "犯罪偵查權", "自治規章制定權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00171', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '為有效打擊恐怖活動，國家擬授權警察於必要時，得以高科技方式下載人民儲存於其個人電 腦中之私人資料，下列敘述何者正確？', '["上述措施雖涉及資訊隱私權，但得逕以行政命令為緊急性之規範", "上述措施涉及國家安全重大公益，警察下載人民資料之方式，不受憲法之限制", "上述措施係為維持社會秩序，警察就下載資料之對象，享有裁量權", "為維持權力制衡及人權保障，對於警察之下載行為，應有適當之事前監督機制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00172', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，關於總統豁免權，下列敘述何者錯誤？', '["豁免權為一種暫時性之程序障礙", "不得以總統為犯罪嫌疑人而進行偵查", "與總統有關之特定處所均不得搜索", "豁免權原則上不得拋棄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00173', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，有關憲法第 15 條保障之生存權、工作權及財產權，下列敘述何者正 確？', '["生存權之內涵僅限於生命權", "工作權之積極面向即為職業自由", "財產權之保障包含繼承權", "營業自由屬工作權保障之範圍，與財產權無關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00174', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法增修條文規定，下列何者享有總統罷免案之提案權？', '["監察委員", "立法委員", "中華民國人民", "司法院大法官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00175', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法及增修條文規定，下列何者不屬於立法院之職權？', '["提出對行政院院長之彈劾案", "追認緊急命令", "提出修憲案", "提出總統罷免案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00176', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依據憲法及增修條文規定與司法院大法官解釋，關於正、副總統之選舉程序，下列敘述何者 錯誤？', '["對於得推薦總統、副總統候選人之政黨，設有最近一次中央民意代表選舉得票率門檻之限 制，合憲", "對未獲政黨推薦之候選人採行連署制度，合憲", "要求被連署人提供保證金新臺幣100萬元，違憲", "總統、副總統候選人應聯名登記，在選票上同列一組圈選，以得票最多之一組為當選"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
